import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User-supplied input

        String baseDir = "/home/user/files/";
        String sanitizedInput = Paths.get(baseDir, userInput).normalize().toString();

        if (!sanitizedInput.startsWith(baseDir)) {
            System.err.println("Invalid file path.");
            return;
        }

        File file = new File(sanitizedInput);

        try (FileInputStream fis = new FileInputStream(file)) {
            // Read and process the file contents
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

